commit 71a0d238867d0d6fa1ca9c1ecb3adf69bea00668
Author: Frank Richter <frank.richter@gmail.com>
Date:   Sat Dec 6 04:00:37 2025 +0100

    Introduce constant for hunk alignment
---
 inc/system/hunk.h | 3 +++
 src/common/bsp.c  | 2 +-
 src/unix/hunk.c   | 4 ++--
 3 files changed, 6 insertions(+), 3 deletions(-)

diff --git a/inc/system/hunk.h b/inc/system/hunk.h
index cc15ef47..e0511810 100644
--- a/inc/system/hunk.h
+++ b/inc/system/hunk.h
@@ -25,6 +25,9 @@ typedef struct {
     size_t  mapped;
 } memhunk_t;

+// hunk allocation alignment is rounded to cacheline
+#define HUNK_ALIGN      64
+
 void    Hunk_Init(void);
 void    Hunk_Begin(memhunk_t *hunk, size_t maxsize);
 void    *Hunk_TryAlloc(memhunk_t *hunk, size_t size);
diff --git a/src/common/bsp.c b/src/common/bsp.c
index 4bcbf0d5..85d5cb85 100644
--- a/src/common/bsp.c
+++ b/src/common/bsp.c
@@ -1432,7 +1432,7 @@ int BSP_Load(const char *name, bsp_t **bsp_p)
         lump_count[i] = count;

         // round to cacheline
-        memsize += ALIGN(count * info->memsize, 64);
+        memsize += ALIGN(count * info->memsize, HUNK_ALIGN);
         maxpos = max(maxpos, end);
     }

diff --git a/src/unix/hunk.c b/src/unix/hunk.c
index c9fb4a02..831aa1b6 100644
--- a/src/unix/hunk.c
+++ b/src/unix/hunk.c
@@ -52,11 +52,11 @@ void *Hunk_TryAlloc(memhunk_t *hunk, size_t size)
 {
     void *buf;

-    Q_assert(size <= SIZE_MAX - 63);
+    Q_assert(size <= SIZE_MAX - (HUNK_ALIGN - 1));
     Q_assert(hunk->cursize <= hunk->maxsize);

     // round to cacheline
-    size = ALIGN(size, 64);
+    size = ALIGN(size, HUNK_ALIGN);
     if (size > hunk->maxsize - hunk->cursize)
         return NULL;

